  `cc_nomcli` varchar(45) NOT NULL DEFAULT '' COMMENT 'nombre del cliente - uno apellido y nombre de table cliente',
  `cc_clavemov` int(7) NOT NULL DEFAULT 0 COMMENT 'Identifica univocamente el movimiento por si hay que modificar en planilla de caja',
  PRIMARY KEY (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=582 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Tabla de movimientos en cuenta corriente';
